$(document).ready((function(){const o=[".btn",".topbar-navitem",".drawer-item"].join(",");$(o).each((function(){const o=$(this),n=$('<span class="state-layer"></span>');o.append(n);const c=o.css("color"),s=o=>c.replace("rgb","rgba").replace(")",`, ${o})`);o.hover((function(){n.css("background-color",s(.08))}),(function(){n.css("background-color","transparent")})),o.on("focusin",(function(){n.css("background-color",s(.1))})),o.on("focusout",(function(){n.css("background-color","transparent")})),o.on("mousedown",(function(){n.css("background-color",s(.1))})),o.on("mouseup",(function(){n.css("background-color",s(.08))}))}));$('<div class="tooltip"></div>').appendTo("body")}));